import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: (project, framework, package) -> version
def build_lookup(data):
    lookup = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(name, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return lookup

bl = build_lookup(baseline)
al = build_lookup(after)

all_keys = sorted(set(bl.keys()) | set(al.keys()))

changes = []
unchanged = []
for k in all_keys:
    bv = bl.get(k)
    av = al.get(k)
    if bv != av:
        changes.append((k[0], k[2], bv or 'N/A', av or 'N/A', k[1]))
    else:
        unchanged.append((k[0], k[2], bv, k[1]))

if changes:
    print('CHANGES:')
    for c in changes:
        print(f'  {c[0]:<20} {c[4]:<10} {c[1]:<50} {c[2]:<12} -> {c[3]}')
else:
    print('NO CHANGES - fully version-neutral')

print()
print(f'UNCHANGED: {len(unchanged)} packages resolve identically to baseline')
"

